/* Smooth page scroll */
html { scroll-behavior: smooth; }

/* Category sections */
.cake-section {
  margin: 2em 0;
  padding: 0.8em 1.2em;
  border-left: 4px solid #f8b4c8;
  background: linear-gradient(135deg, #fff5f7 0%, #ffffff 100%);
  border-radius: 0 8px 8px 0;
}
.cake-section h2 { margin-top: 0; }

/* Gallery grid */
.cake-gallery {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 14px;
  margin: 1em 0;
  align-items: start;
}

/* Each card -- scroll-unfurl on hover */
.cake-item {
  position: relative;
  overflow: hidden;
  border-radius: 10px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  background: #fff;
  max-height: 260px;
  transition: max-height 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94),
              box-shadow 0.3s;
  z-index: 1;
}
.cake-item:hover {
  max-height: 800px;
  box-shadow: 0 8px 24px rgba(0,0,0,0.18);
  z-index: 10;
}

/* Image -- natural size, clipped by card */
.cake-item img {
  width: 100%;
  display: block;
  transition: filter 0.3s;
}
.cake-item:hover img {
  filter: brightness(1.05);
}

/* Reset constraints when mediumzoom opens the image */
img.medium-zoom-image--opened {
  max-height: none !important;
  object-fit: contain !important;
  border-radius: 0 !important;
}

/* Caption overlay -- rides the bottom edge as card unfurls */
.cake-item .caption {
  position: absolute;
  bottom: 0; left: 0; right: 0;
  padding: 8px 10px;
  background: linear-gradient(transparent, rgba(0,0,0,0.65));
  color: #fff;
  font-size: 0.82em;
  line-height: 1.4;
  opacity: 0;
  transition: opacity 0.3s;
}
.cake-item:hover .caption {
  opacity: 1;
}

/* Responsive */
@media (max-width: 900px) {
  .cake-gallery { grid-template-columns: repeat(2, 1fr); }
}
@media (max-width: 500px) {
  .cake-gallery { grid-template-columns: 1fr; }
}


